package main

import (
	"os/exec"
	"regexp"
	"strconv"
	"strings"
	"time"
	"errors"
	"fmt"
)

// MeasureLatency measures the average latency to a host by sending ping packets
// and parsing the results to extract average round-trip time in milliseconds
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, errors.New("count must be greater than 0")
	}

	// Execute ping command with specified count
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), "-w", strconv.Itoa(count*2), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %v", err)
	}

	outputStr := string(output)

	// Parse the ping output to extract average latency
	// Pattern to match: "rtt min/avg/max/mdev = X.XXX/X.XXX/X.XXX/X.XXX ms"
	// Also handles: "round-trip min/avg/max/stddev = X.XXX/X.XXX/X.XXX/X.XXX ms"
	patterns := []string{
		`rtt min/avg/max/mdev = (\d+\.?\d*)/(\d+\.?\d*)/(\d+\.?\d*)/(\d+\.?\d*)`,
		`round-trip min/avg/max/stddev = (\d+\.?\d*)/(\d+\.?\d*)/(\d+\.?\d*)/(\d+\.?\d*)`,
	}

	var avgLatency float64
	found := false

	for _, pattern := range patterns {
		re := regexp.MustCompile(pattern)
		matches := re.FindStringSubmatch(outputStr)

		if matches != nil && len(matches) >= 3 {
			// matches[2] contains the average latency value
			avgLatency, err = strconv.ParseFloat(matches[2], 64)
			if err == nil {
				found = true
				break
			}
		}
	}

	if !found {
		return 0, errors.New("could not parse average latency from ping output")
	}

	// Add a small delay to prevent rapid successive calls
	time.Sleep(100 * time.Millisecond)

	return avgLatency, nil
}

func main() {
	// Example usage demonstration
	hosts := []string{
		"google.com",
		"8.8.8.8",
		"cloudflare.com",
	}

	for _, host := range hosts {
		fmt.Printf("Measuring latency to %s...\n", host)

		avgLatency, err := MeasureLatency(host, 4)
		if err != nil {
			fmt.Printf("Error measuring latency to %s: %v\n", host, err)
		} else {
			fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
		}

		// Add delay between tests
		time.Sleep(time.Second)
	}
}

