package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency measures the average latency to a host by sending multiple ping requests
// and returns the average latency in milliseconds along with any errors encountered.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}

	// Execute ping command with specified host and count
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping failed: %v, stderr: %s", err, stderr.String())
	}

	output := stdout.String()
	lines := strings.Split(output, "\n")
	var latencies []float64

	// Parse ping output to extract latency values
	for _, line := range lines {
		if strings.Contains(line, "time=") {
			// Extract the time value from lines containing "time="
			fields := strings.Fields(line)
			for _, field := range fields {
				if strings.HasPrefix(field, "time=") {
					timeStr := strings.TrimPrefix(field, "time=")
					// Remove any trailing characters that aren't part of the number
					timeStr = strings.TrimSuffix(timeStr, " ms")
					latency, err := strconv.ParseFloat(timeStr, 64)
					if err != nil {
						continue // Skip invalid time values
					}
					latencies = append(latencies, latency)
				}
			}
		}
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no successful ping responses")
	}

	// Calculate average latency
	sum := float64(0)
	for _, latency := range latencies {
		sum += latency
	}
	avgLatency := sum / float64(len(latencies))

	return avgLatency, nil
}

func main() {
	// Check command line arguments
	if len(os.Args) != 3 {
		fmt.Printf("Usage: %s <host> <count>\n", os.Args[0])
		fmt.Println("Example: ./latency 8.8.8.8 5")
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Printf("Error: count must be an integer\n")
		os.Exit(1)
	}

	// Measure latency to the specified host
	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

