package main

import (
	"bytes"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings a host a specified number of times and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	// Determine the correct flag for the number of pings based on the OS
	flag := "-c"
	if runtime.GOOS == "windows" {
		flag = "-n"
	}

	// Build the ping command with the appropriate flag and arguments
	cmd := exec.Command("ping", flag, strconv.Itoa(count), host)

	// Capture the command output
	var output bytes.Buffer
	cmd.Stdout = &output

	// Execute the ping command
	if err := cmd.Run(); err != nil {
		return 0, fmt.Errorf("failed to execute ping: %v", err)
	}

	// Extract latency values from the output using a regular expression
	// Matches patterns like "time=13.8 ms" or "time=13ms"
	pattern := regexp.MustCompile(`time=([0-9.]+)`)
	matches := pattern.FindAllStringSubmatch(output.String(), -1)

	// Calculate the sum of all latency values
	total := 0.0
	countParsed := 0
	for _, match := range matches {
		if len(match) < 2 {
			continue
		}
		// Convert the extracted string to a float64
		latency, err := strconv.ParseFloat(match[1], 64)
		if err != nil {
			continue
		}
		total += latency
		countParsed++
	}

	// Return an error if no valid latency values were found
	if countParsed == 0 {
		return 0, fmt.Errorf("no successful pings")
	}

	// Compute and return the average latency
	return total / float64(countParsed), nil
}

func main() {
	// Example usage: Ping Google DNS server 3 times
	avgLatency, err := MeasureLatency("8.8.8.8", 3)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Average latency: %.2f ms\n", avgLatency)
}

