package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency measures the average network latency to a host
func MeasureLatency(host string, count int) (float64, error) {
	// Validate input parameters
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Execute ping command with specified count
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping failed: %v, stderr: %s", err, stderr.String())
	}

	// Parse output for latency values
	output := stdout.String()
	lines := strings.Split(output, "\n")
	var times []float64

	for _, line := range lines {
		// Look for lines containing "time=" followed by numeric value
		if strings.Contains(line, "time=") {
			fields := strings.Fields(line)
			for _, field := range fields {
				if strings.HasPrefix(field, "time=") {
					// Extract numeric value after "time="
					timeStr := strings.TrimPrefix(field, "time=")
					// Remove trailing units like "ms" if present
					timeStr = strings.TrimSpace(timeStr)
					if strings.HasSuffix(timeStr, "ms") {
						timeStr = strings.TrimSuffix(timeStr, "ms")
					}

					// Parse the numeric value
					t, err := strconv.ParseFloat(timeStr, 64)
					if err == nil {
						times = append(times, t)
					}
				}
			}
		}
	}

	// Calculate average latency
	if len(times) == 0 {
		return 0, fmt.Errorf("no latency measurements found")
	}

	total := 0.0
	for _, t := range times {
		total += t
	}
	avgLatency := total / float64(len(times))

	return avgLatency, nil
}

func main() {
	// Get command line arguments
	if len(os.Args) < 3 {
		fmt.Println("Usage: go run main.go <host> <count>")
		fmt.Println("Example: go run main.go google.com 4")
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Println("Error: count must be a valid integer")
		os.Exit(1)
	}

	// Measure latency
	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, latency)
}

