// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds
func MeasureLatency(host string, count int) (float64, error) {
	// Validate inputs
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}

	// Build the ping command with specified count
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	// Execute the command and capture output
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping failed: %v\nOutput: %s", err, string(output))
	}

	// Parse the ping output to extract latency values
	latencyValues, err := parsePingOutput(string(output))
	if err != nil {
		return 0, err
	}

	// Calculate average latency
	if len(latencyValues) == 0 {
		return 0, fmt.Errorf("no latency values found in ping output")
	}

	total := 0.0
	for _, latency := range latencyValues {
		total += latency
	}
	average := total / float64(len(latencyValues))

	return average, nil
}

// parsePingOutput extracts latency values from ping command output
func parsePingOutput(output string) ([]float64, error) {
	var latencies []float64

	// Pattern to match ping time output (e.g., "time=10.5 ms" or "time=10.5")
	// Works with both Linux and macOS ping output
	timePattern := regexp.MustCompile(`time=([\d.]+)\s*ms`)

	lines := strings.Split(output, "\n")
	for _, line := range lines {
		matches := timePattern.FindStringSubmatch(line)
		if len(matches) >= 2 {
			latency, err := strconv.ParseFloat(matches[1], 64)
			if err != nil {
				continue // Skip invalid values
			}
			latencies = append(latencies, latency)
		}
	}

	return latencies, nil
}

