// MeasureLatency measures the average latency to a specified host by sending ping requests.
// It returns the average round-trip time in milliseconds and any error encountered.
//
// Parameters:
//   - host: The target host to ping (IP address or hostname)
//   - count: Number of ping attempts to make
//
// Returns:
//   - float64: Average latency in milliseconds
//   - error: Error if ping fails or no valid responses are received
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("invalid ping count: must be positive")
	}

	// Build ping command arguments based on OS
	var args []string
	if runtime.GOOS == "windows" {
		args = []string{"-n", strconv.Itoa(count), host}
	} else {
		args = []string{"-c", strconv.Itoa(count), host}
	}

