	if len(os.Args) < 2 {
		fmt.Println("Usage: latency <host> [count]")
		fmt.Println("  host:  Target host to ping (IP or hostname)")
		fmt.Println("  count: Number of ping attempts (default: 3)")
		os.Exit(1)
	}

	host := os.Args[1]
	count := 3

