// MeasureLatency measures the average network latency to a host
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Determine the command based on OS
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the command
	output, err := cmd.CombinedOutput()
	if err != nil {
		// Still process output even if command returns error
	}

	// Parse the output to extract latency values
	times := parseLatency(string(output))
	if len(times) == 0 {
		return 0, errors.New("no valid latency measurements found")
	}

	// Calculate average latency
	sum := 0.0
	for _, t := range times {
		sum += t
	}
	return sum / float64(len(times)), nil
}

// parseLatency extracts latency values from ping command output
func parseLatency(output string) []float64 {
	// Regex patterns for different ping output formats
	patterns := []string{
		`time\s*=\s*([0-9.]+)\s*ms`,      // Unix format
		`time\s*=\s*([0-9.]+)ms`,         // Unix format without space
		`time=([0-9.]+)ms`,               // Windows format
		`time\s*=\s*([0-9.]+)`,           // Generic format
	}

	var times []float64
	for _, pattern := range patterns {
		re := regexp.MustCompile(pattern)
		matches := re.FindAllStringSubmatch(output, -1)
		for _, match := range matches {
			if len(match) > 1 {
				if t, err := strconv.ParseFloat(match[1], 64); err == nil {
					times = append(times, t)
				}
			}
		}
		if len(times) > 0 {
			break
		}
	}

	return times
}

func main() {
	if len(os.Args) < 3 {
		fmt.Println("Usage: go run main.go <host> <count>")
		fmt.Println("Example: go run main.go google.com 4")
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil || count <= 0 {
		fmt.Println("Error: count must be a positive integer")
		os.Exit(1)
	}

	fmt.Printf("Measuring latency to %s with %d ping attempts...\n", host, count)

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency: %.2f ms\n", avg)
}

