package main

import (
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
)

// MeasureLatency pings the specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, nil
	}

	// Build the ping command with the specified count
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, runErr := cmd.CombinedOutput()

	// Parse the output for time values
	re := regexp.MustCompile(`time=([0-9]+\.?[0-9]*)`)
	matches := re.FindAllStringSubmatch(string(output), -1)

	if len(matches) == 0 {
		if runErr != nil {
			return 0, runErr
		}
		return 0, fmt.Errorf("no successful ping responses")
	}

	total := 0.0
	for _, match := range matches {
		if len(match) < 2 {
			continue
		}
		val, err := strconv.ParseFloat(match[1], 64)
		if err != nil {
			// Skip if we cannot parse
			continue
		}
		total += val
	}

	avg := total / float64(len(matches))
	return avg, nil
}

func main() {}

