package main

import (
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings a host a specified number of times and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	// Build the ping command: ping -c <count> <host>
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	// Execute the command and capture combined output (stdout and stderr)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, err
	}

	// Convert output to string for parsing
	outputStr := string(output)

	// Regex pattern to match both Linux and macOS ping summary formats
	// Matches lines like:
	//   rtt min/avg/max/mdev = 10.123/20.456/30.789/5.123 ms
	//   round-trip min/avg/max/stddev = 10.123/20.456/30.789/5.123 ms
	pattern := `(?:rtt min/avg/max/mdev|round-trip min/avg/max/stddev) = \d+\.\d+/(\d+\.\d+)/\d+\.\d+/\d+\.\d+ ms`
	re := regexp.MustCompile(pattern)

	// Process output line by line from end to find the summary line
	lines := strings.Split(outputStr, "\n")
	for i := len(lines) - 1; i >= 0; i-- {
		line := lines[i]
		matches := re.FindStringSubmatch(line)
		if matches != nil {
			avgStr := matches[1]
			avg, err := strconv.ParseFloat(avgStr, 64)
			if err != nil {
				return 0, fmt.Errorf("failed to parse average latency value: %s", avgStr)
			}
			return avg, nil
		}
	}

	// If no summary line was found, return an error
	return 0, fmt.Errorf("could not find ping summary in output")
}

func main() {
	// Example usage: measure latency to google.com with 4 ping attempts
	host := "google.com"
	count := 4

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

