package main

import (
	"bytes"
	"fmt"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
)

func MeasureLatency(host string, count int) (float64, error) {
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	var output bytes.Buffer
	cmd.Stdout = &output
	cmd.Stderr = &output

	err := cmd.Run()
	if err != nil {
		if exitError, ok := err.(*exec.ExitError); ok {
			return 0, fmt.Errorf("ping failed with exit code %d: %s", exitError.ExitCode(), output.String())
		}
		return 0, err
	}

	outStr := output.String()
	lines := strings.Split(outStr, "\n")

	for i := len(lines) - 1; i >= 0; i-- {
		line := strings.TrimSpace(lines[i])
		if line == "" {
			continue
		}

		if runtime.GOOS == "windows" {
			if strings.HasPrefix(line, "Average =") {
				parts := strings.SplitN(line, "=", 2)
				if len(parts) < 2 {
					continue
				}
				afterEq := strings.TrimSpace(parts[1])
				if strings.HasSuffix(afterEq, "ms") {
					afterEq = afterEq[:len(afterEq)-2]
				}
				avg, err := strconv.ParseFloat(afterEq, 64)
				if err != nil {
					return 0, fmt.Errorf("failed to parse average latency: %v", err)
				}
				return avg, nil
			}
		} else {
			if strings.HasPrefix(line, "rtt min/avg/max") {
				parts := strings.SplitN(line, "=", 2)
				if len(parts) < 2 {
					continue
				}
				afterEq := strings.TrimSpace(parts[1])
				tokens := strings.Fields(afterEq)
				if len(tokens) < 1 {
					continue
				}
				nums := strings.Split(tokens[0], "/")
				if len(nums) < 2 {
					continue
				}
				avg, err := strconv.ParseFloat(nums[1], 64)
				if err != nil {
					return 0, fmt.Errorf("failed to parse average latency: %v", err)
				}
				return avg, nil
			}
		}
	}

	return 0, fmt.Errorf("could not find ping statistics in output")
}

func main() {
	host := "google.com"
	count := 4
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}
	fmt.Printf("Average latency to %s: %.2f ms\n", host, avg)
}

