// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds
func MeasureLatency(host string, count int) (float64, error) {
	// Validate inputs
	if count <= 0 {
		return 0, &ValidationError{Message: "count must be greater than 0"}
	}

	if strings.TrimSpace(host) == "" {
		return 0, &ValidationError{Message: "host cannot be empty"}
	}

	// Execute ping command with timeout
	ctx, cancel := contextWithTimeout(10 * time.Second)
	defer cancel()

	cmd := exec.CommandContext(ctx, "ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()

	if err != nil {
		// Check if it's a timeout
		if ctx.Err() == context.DeadlineExceeded {
			return 0, &TimeoutError{Message: "ping timed out"}
		}
		return 0, &PingError{Message: "ping command failed", OriginalError: err}
	}

	// Parse ping output to extract latency values
	latencies, err := parsePingOutput(string(output))
	if err != nil {
		return 0, err
	}

	if len(latencies) == 0 {
		return 0, &NoResponseError{Message: "no successful pings received"}
	}

	// Calculate average latency
	totalLatency := 0.0
	for _, latency := range latencies {
		totalLatency += latency
	}
	averageLatency := totalLatency / float64(len(latencies))

	return averageLatency, nil
}

// parsePingOutput extracts latency values from ping command output
func parsePingOutput(output string) ([]float64, error) {
	latencies := []float64{}

	// Match patterns like: "time=10.5 ms" or "time=15.2ms"
	re := regexp.MustCompile(`time[=<]\s*(\d+\.?\d*)\s*ms`)

	lines := strings.Split(output, "\n")
	for _, line := range lines {
		matches := re.FindStringSubmatch(line)
		if len(matches) > 1 {
			latency, err := strconv.ParseFloat(matches[1], 64)
			if err != nil {
				continue // Skip lines with parsing errors
			}
			latencies = append(latencies, latency)
		}
	}

	return latencies, nil
}

// contextWithTimeout creates a context with timeout (Go 1.24 compatible)
func contextWithTimeout(duration time.Duration) (context.Context, context.CancelFunc) {
	return context.WithTimeout(context.Background(), duration)
}

// Custom error types
type ValidationError struct {
	Message string
}

func (e *ValidationError) Error() string {
	return "validation error: " + e.Message
}

type TimeoutError struct {
	Message string
}

func (e *TimeoutError) Error() string {
	return "timeout error: " + e.Message
}

type PingError struct {
	Message      string
	OriginalError error
}

func (e *PingError) Error() string {
	if e.OriginalError != nil {
		return e.Message + ": " + e.OriginalError.Error()
	}
	return e.Message
}

type NoResponseError struct {
	Message string
}

func (e *NoResponseError) Error() string {
	return e.Message
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	fmt.Printf("Measuring latency to %s with %d pings...\n", host, count)

	averageLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, averageLatency)
}

